# Query Perplexity for supplemental veteran transition intel - mask API key
RESPONSE=$(curl -s -X POST "https://api.perplexity.ai/chat/completions" \
  -H "Authorization: Bearer $PERPLEXITY_API_KEY" \
  -H "Content-Type: application/json" \
  -d '{
    "model": "sonar",
    "messages": [
      {"role": "user", "content": "What are the most important veteran transition, VA policy, and military employment news stories from the past week (March 5-12, 2026)? Give me 3-5 bullet points with source URLs."}
    ]
  }' 2>&1)
echo "$RESPONSE" | node -e "
const data = JSON.parse(require('fs').readFileSync('/dev/stdin','utf8'));
if (data.choices) {
  console.log(data.choices[0].message.content);
} else {
  console.log('Error:', JSON.stringify(data).substring(0,200));
}
" 2>&1

