# Check if TELEGRAM vars exist in the SECRETS JSON (AGENT_ prefix secrets)
echo "$SECRETS" | node -e "
const s = JSON.parse(require('fs').readFileSync('/dev/stdin','utf8'));
const tgKeys = Object.keys(s).filter(k => k.includes('TELEGRAM'));
if (tgKeys.length > 0) {
  console.log('Found Telegram keys:', tgKeys.join(', '));
  // Export them for use
  tgKeys.forEach(k => {
    if (k.includes('TOKEN')) process.stdout.write('HAS_TOKEN=true\n');
    if (k.includes('CHAT')) process.stdout.write('HAS_CHAT=true\n');
  });
} else {
  console.log('No Telegram keys found in SECRETS');
  console.log('Available keys:', Object.keys(s).join(', '));
}
" 2>&1
